<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script>
function phistError(m){$('.isi_warning_delete').text(m||'Performance History gagal diproses.');$('.error_data_delete').fadeIn();}
function phistFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),cycle_year:$('#filter_cycle_year').val(),appraisal_period:$('#filter_appraisal_period').val(),employee_id:$('#filter_employee_id').val(),department_code:$('#filter_department_code').val(),job_title_id:$('#filter_job_title_id').val(),final_rating:$('#filter_final_rating').val(),history_status:$('#filter_history_status').val(),audit_source:$('#filter_audit_source').val(),impact_type:$('#filter_impact_type').val(),keyword:$('#filter_keyword').val()};}
function phistAjax(s,act,p){$(s).select2({width:'100%',allowClear:true,placeholder:p,ajax:{url:'<?=base_admin();?>modul/performance_history/performance_history_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
$(function(){if($.fn.datepicker){$('.phist-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_cycle_year,#filter_appraisal_period,#filter_final_rating,#filter_history_status,#filter_audit_source,#filter_impact_type').select2({width:'100%',allowClear:true});phistAjax('#filter_employee_id','employee_search','Semua Employee');phistAjax('#filter_department_code','department_search','Semua Department');phistAjax('#filter_job_title_id','job_title_search','Semua Job Title');}
var dt=$('#dtb_performance_history').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'70px',targets:1}],ajax:{url:'<?=base_admin();?>modul/performance_history/performance_history_data.php',type:'post',data:function(d){$.extend(d,phistFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_employees').text(k.employees||0);$('#kpi_avg').text(k.avg_score||0);$('#kpi_locked').text(k.locked||0);$('#kpi_high').text(k.high||0);$('#kpi_pip').text(k.pip||0);return j.data||[];},error:function(x){console.log(x.responseText);phistError('Data Performance History gagal dimuat.');}}});
$('#btn_filter_phist').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_phist').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_cycle_year').val('<?=$yearNow;?>').trigger('change');$('#filter_appraisal_period,#filter_employee_id,#filter_department_code,#filter_job_title_id,#filter_final_rating,#filter_history_status,#filter_audit_source,#filter_impact_type').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_phist').click(function(){window.location='<?=base_admin();?>modul/performance_history/performance_history_action.php?act=export&'+$.param(phistFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$(document).on('click','.btn-phist-detail',function(){$.post('<?=base_admin();?>modul/performance_history/performance_history_action.php?act=detail',{id:$(this).data('id')},function(h){$('#phist_detail_body').html(h);$('#modal_phist_detail').modal('show');});});
});
</script>
